mapper.select:
SELECT 
FROM tb_veh_certificate t
WHERE t.row_valid = 1

    AND t.id = #{id}


    AND t.request_id = #{requestId}


    AND t.vin = #{vin}


    AND t.cert_sn = #{certSn}


    AND t.device_sn = #{deviceSn}


    AND t.cert_status = #{certStatus}


    AND t.description = #{description}


    AND t.create_time = #{createTime}


    AND t.create_by = #{createBy}


    AND t.modify_time = #{modifyTime}


    AND t.modify_by = #{modifyBy}


    AND t.row_version = #{rowVersion}

ORDER BY t.id DESC

SELECT 
FROM tb_veh_certificate t
WHERE t.row_valid = 1


    AND t.vin = #{vin}


    AND t.request_id = #{requestId}


    AND t.cert_sn = #{certSn}


    AND t.device_sn = #{deviceSn}


    AND t.cert_status = #{certStatus}


    AND t.id < #{beginId}

ORDER BY t.id DESC

    LIMIT #{pageSize}

SELECT 
FROM tb_veh_certificate t
WHERE t.row_valid = 1
AND t.modify_time > #{updatedAfter}
ORDER BY t.modify_time ASC
LIMIT #{limit}
